#! /usr/bin/perl
# chkmtime

my $file = "mmaptest.f";

my ($ctime, $mtime);

for(;;)
{
        my @stat = stat $file;

        if ($stat[1] <= 0)
        {
                print 'Cannot stat file ', $file, "\n";
                exit 1;
        }

        if ($stat[9] != $mtime || $stat[10] != $ctime)
        {
                print scalar localtime, "\n",
                        '  mtime = ', scalar localtime($stat[9]), "\n",
                        '  ctime = ', scalar localtime($stat[10]), "\n";
                $mtime = $stat[9];
                $ctime = $stat[10];
        }

        sleep(60);
}
